        + "  privacy_boundary: standard_or_shared_only\n"
        + "  freshness: created_at_required\n"
        + "  conflict_behavior: guardian_wins\n"
        + "  suppression_rules:\n"
        + "    - stale_provider_evidence\n"
        + "    - irrelevant_provider_evidence\n"
